INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Acolyte', 'Acolyte', 'Medium', 'Humanoid (Any Race)', 'Any Alignment', 10, 9, '2d8', '30 Ft.', 10, 10, 10, 10, 14, 11, NULL, NULL, NULL, NULL, NULL, NULL, 'Medicine +4, Religion +2', NULL, NULL, NULL, 'Passive Perception 12', 'any one language (usually Common)', '1/4', 50, 2, '[{"name": "Club", "desc": "Melee Weapon Attack: +2 to hit, reach 5 ft., one target. Hit: 2 (1d4) bludgeoning damage.", "attackBonus": 2, "damageDice": "1d4", "damageBonus": 0, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Spellcasting", "desc": "The acolyte is a 1st-level spellcaster. Its spellcasting ability is Wisdom (spell save DC 12, +4 to hit with spell attacks). The acolyte has following cleric spells prepared:\\n\\n\\u2022 Cantrips (at will): light, sacred flame, thaumaturgy\\n\\u2022 1st level (3 slots): bless, cure wounds, sanctuary", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Adult Blue Dracolich', 'Adult Blue Dracolich', 'Huge', 'Undead', 'Lawful Evil', 19, 225, '18d12', '40 Ft., Burrow 30 Ft., Fly 80 Ft.', 25, 10, 23, 16, 15, 19, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +12', 'Necrotic', 'Lightning, Poison; Charmed, Exhaustion, Frightened, Paralyzed, Poisoned', NULL, 'Blindsight 60 Ft., Darkvision 120 Ft., Passive Perception 22', 'Common, Draconic', '17', 18000, 6, '[{"name": "Multiattack", "desc": "The dracolich can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 3, "healAmount": 0}, {"name": "Bite", "desc": "Melee Weapon Attack: +12 to hit, reach 10 ft., one target. Hit: 18 (2d10 + 7) piercing damage plus 5 (1d10) lightning damage.", "attackBonus": 12, "damageDice": "2d10 + 1d10", "damageBonus": 7, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Claw", "desc": "Melee Weapon Attack: +12 to hit, reach 5 ft., one target. Hit: 14 (2d6 + 7) slashing damage.", "attackBonus": 12, "damageDice": "2d6", "damageBonus": 7, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tail", "desc": "Melee Weapon Attack: +12 to hit, reach 15 ft., one target. Hit: 16 (2d8 + 7) bludgeoning damage.", "attackBonus": 12, "damageDice": "2d8", "damageBonus": 7, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Frightful Presence", "desc": "Each creature of the dracolich\'s choice that is within 120 feet of the dracolich and aware of it must succeed on a DC 18 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature\'s saving throw is successful or the effect ends for it, the creature is immune to the dracolich\'s Frightful Presence for the next 24 hours.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Lightning Breath (Recharge 5-6)", "desc": "The dracolich exhales lightning in a 90-foot line that is 5 feet wide. Each creature in that line must make a DC 20 Dexterity saving throw, taking 66 (12d10) lightning damage on a failed save, or half as much damage on a successful one.", "attackBonus": 0, "damageDice": "12d10", "damageBonus": 0, "damageType": "lightning", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "dex", "saveAbilityLabel": "Dexterity", "saveDC": 20, "rangeSquares": 18, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Legendary Resistance (3/Day)", "desc": "If the dracolich fails a saving throw, it can choose to succeed instead.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Magic Resistance", "desc": "The dracolich has advantage on saving throws against spells and other magical effects.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Detect", "desc": "The dracolich makes a Wisdom (Perception) check.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tail Attack", "desc": "The dracolich makes a tail attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Wing Attack (Costs 2 Actions)", "desc": "The dracolich beats its tattered wings. Each creature within 10 ft. of the dracolich must succeed on a DC 21 Dexterity saving throw or take 14 (2d6 + 7) bludgeoning damage and be knocked prone. After beating its wings this way, the dracolich can fly up to half its flying speed.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Androsphinx', 'Androsphinx', 'Large', 'Monstrosity', 'Lawful Neutral', 17, 199, '19d10', '40 Ft., Fly 60 Ft.', 22, 10, 20, 16, 18, 23, NULL, 6, 11, 9, 10, NULL, 'Arcana +9, Perception +10, Religion +15', NULL, 'Psychic; Bludgeoning, Piercing, And Slashing From Nonmagical Weapons; Charmed, Frightened', NULL, 'Truesight 120 Ft., Passive Perception 20', 'Common, Sphinx', '17', 18000, 6, '[{"name": "Multiattack", "desc": "The sphinx makes two claw attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Claw", "desc": "Melee Weapon Attack: +12 to hit, reach 5 ft., one target. Hit: 17 (2d10 + 6) slashing damage.", "attackBonus": 12, "damageDice": "2d10", "damageBonus": 6, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Roar (3/Day)", "desc": "The sphinx emits a magical roar. Each time it roars before finishing a long rest, the roar is louder and the effect is different, as detailed below. Each creature within 500 feet of the sphinx and able to hear the roar must make a saving throw.\\n\\nFirst Roar. Each creature that fails a DC 18 Wisdom saving throw is frightened for 1 minute. A frightened creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.\\n\\nSecond Roar. Each creature that fails a DC 18 Wisdom saving throw is deafened and frightened for 1 minute. A frightened creature is paralyzed and can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.\\n\\nThird Roar. Each creature makes a DC 18 Constitution saving throw. On a failed save, a creature takes 44 (8d10) thunder damage and is knocked prone. On a successful save, the creature takes half as much damage and isn\'t knocked prone.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Inscrutable", "desc": "The sphinx is immune to any effect that would sense its emotions or read its thoughts, as well as any divination spell that it refuses. Wisdom (Insight) checks made to ascertain the sphinx\'s intentions or sincerity have disadvantage.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Magic Weapons", "desc": "The sphinx\'s weapon attacks are magical.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "The sphinx is a 12th-level spellcaster. Its spellcasting ability is Wisdom (spell save DC 18, +10 to hit with spell attacks). It requires no material components to cast its spells. The sphinx has the following cleric spells prepared:\\n\\n\\u2022 Cantrips (at will): sacred flame, spare the dying, thaumaturgy\\n\\u2022 1st level (4 slots): command, detect evil and good, detect magic\\n\\u2022 2nd level (3 slots): lesser restoration, zone of truth\\n\\u2022 3rd level (3 slots): dispel magic, tongues\\n\\u2022 4th level (3 slots): banishment, freedom of movement\\n\\u2022 5th level (2 slots): flame strike, greater restoration\\n\\u2022 6th level (1 slot): heroes\' feast", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Claw Attack", "desc": "The sphinx makes one claw attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Teleport (Costs 2 Actions)", "desc": "The sphinx magically teleports, along with any equipment it is wearing or carrying, up to 120 feet to an unoccupied space it can see.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Cast a Spell (Costs 3 Actions)", "desc": "The sphinx casts a spell from its list of prepared spells, using a spell slot as normal.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Ape', 'Ape', 'Medium', 'Beast', 'Unaligned', 12, 19, '3d8', '30 Ft., Climb 30 Ft.', 16, 14, 14, 6, 12, 7, NULL, NULL, NULL, NULL, NULL, NULL, 'Athletics +5, Perception +3', NULL, NULL, NULL, 'Passive Perception 13', '', '1/2', 100, 2, '[{"name": "Multiattack", "desc": "The ape makes two fist attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Fist", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 6 (1d6 + 3) bludgeoning damage.", "attackBonus": 5, "damageDice": "1d6", "damageBonus": 3, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Rock", "desc": "Ranged Weapon Attack: +5 to hit, range 25/50 ft., one target. Hit: 6 (1d6 + 3) bludgeoning damage.", "attackBonus": 5, "damageDice": "1d6", "damageBonus": 3, "damageType": "bludgeoning", "category": "ranged", "normalRange": 5, "longRange": 10, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Azer', 'Azer', 'Medium', 'Elemental', 'Lawful Neutral', 17, 39, '6d8', '30 Ft.', 17, 12, 15, 12, 13, 10, NULL, NULL, 4, NULL, NULL, NULL, NULL, NULL, 'Fire, Poison; Poisoned', NULL, 'Passive Perception 11', 'Ignan', '2', 450, 2, '[{"name": "Warhammer", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 7 (1d8 + 3) bludgeoning damage, or 8 (1d10 + 3) bludgeoning damage if used with two hands to make a melee attack, plus 3 (1d6) fire damage.", "attackBonus": 5, "damageDice": "1d8 + 1d6", "damageBonus": 3, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Heated Body", "desc": "A creature that touches the azer or hits it with a melee attack while within 5 ft. of it takes 5 (1d10) fire damage.", "attackBonus": 0, "damageDice": "1d10", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Heated Weapons", "desc": "When the azer hits with a metal melee weapon, it deals an extra 3 (1d6) fire damage (included in the attack).", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Illumination", "desc": "The azer sheds bright light in a 10-foot radius and dim light for an additional 10 ft..", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
