    ('Baboon', 'Baboon', 'Small', 'Beast', 'Unaligned', 12, 3, '1d6', '30 Ft., Climb 30 Ft.', 8, 14, 11, 4, 12, 6, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Passive Perception 11', '', '0', 10, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +1 to hit, reach 5 ft., one target. Hit: 1 (1d4 \\u2014 1) piercing damage.", "attackBonus": 1, "damageDice": "1d4", "damageBonus": -1, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Pack Tactics", "desc": "The baboon has advantage on an attack roll against a creature if at least one of the baboon\'s allies is within 5 ft. of the creature and the ally isn\'t incapacitated.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
