    ('Giant Frog', 'Giant Frog', 'Medium', 'Beast', 'Unaligned', 11, 18, '4d8', '30 Ft., Swim 30 Ft.', 12, 13, 11, 2, 10, 3, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +2, Stealth +3', NULL, NULL, NULL, 'Darkvision 30 Ft., Passive Perception 12', '', '1/4', 50, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +3 to hit, reach 5 ft., one target. Hit: 4 (1d6 + 1) piercing damage, and the target is grappled (escape DC 11). Until this grapple ends, the target is restrained, and the frog can\'t bite another target.", "attackBonus": 3, "damageDice": "1d6", "damageBonus": 1, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Swallow", "desc": "The frog makes one bite attack against a Small or smaller target it is grappling. If the attack hits, the target is swallowed, and the grapple ends. The swallowed target is blinded and restrained, it has total cover against attacks and other effects outside the frog, and it takes 5 (2d4) acid damage at the start of each of the frog\'s turns. The frog can have only one target swallowed at a time. If the frog dies, a swallowed creature is no longer restrained by it and can escape from the corpse using 5 ft. of movement, exiting prone.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Amphibious", "desc": "The frog can breathe air and water", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Standing Leap", "desc": "The frog\'s long jump is up to 20 ft. and its high jump is up to 10 ft., with or without a running start.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
