    ('Giant Octopus', 'Giant Octopus', 'Large', 'Beast', 'Unaligned', 11, 52, '8d10', '10 Ft., Swim 60 Ft.', 17, 13, 13, 4, 10, 4, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +4, Stealth +5', NULL, NULL, NULL, 'Darkvision 60 Ft., Passive Perception 14', '', '1', 200, 2, '[{"name": "Tentacles", "desc": "Melee Weapon Attack: +5 to hit, reach 15 ft., one target. Hit: 10 (2d6 + 3) bludgeoning damage. If the target is a creature, it is grappled (escape DC 16). Until this grapple ends, the target is restrained, and the octopus can\'t use its tentacles on another target.", "attackBonus": 5, "damageDice": "2d6", "damageBonus": 3, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Ink Cloud (Recharges after a Short or Long Rest)", "desc": "A 20-foot-radius cloud of ink extends all around the octopus if it is underwater. The area is heavily obscured for 1 minute, although a significant current can disperse the ink. After releasing the ink, the octopus can use the Dash action as a bonus action.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Hold Breath", "desc": "While out of water, the octopus can hold its breath for 1 hour.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Underwater Camouflage", "desc": "The octopus has advantage on Dexterity (Stealth) checks made while underwater.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Water Breathing", "desc": "The octopus can breathe only underwater.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
