    ('Giant Poisonous Snake', 'Giant Poisonous Snake', 'Medium', 'Beast', 'Unaligned', 14, 11, '2d8', '30 Ft., Swim 30 Ft.', 10, 18, 13, 2, 10, 3, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +2', NULL, NULL, NULL, 'Blindsight 10 Ft., Passive Perception 12', '', '1/4', 50, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +6 to hit, reach 10 ft., one target. Hit: 6 (1d4 + 4) piercing damage, and the target must make a DC 11 Constitution saving throw, taking 10 (3d6) poison damage on a failed save, or half as much damage on a successful one.", "attackBonus": 6, "damageDice": "1d4", "damageBonus": 4, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
