    ('Giant Scorpion', 'Giant Scorpion', 'Large', 'Beast', 'Unaligned', 15, 52, '7d10', '40 Ft.', 15, 13, 15, 1, 9, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Blindsight 60 Ft., Passive Perception 9', '', '3', 700, 2, '[{"name": "Claw", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 6 (1d8 + 2) bludgeoning damage, and the target is grappled (escape DC 12). The scorpion has two claws, each of which can grapple only one target.", "attackBonus": 4, "damageDice": "1d8", "damageBonus": 2, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Multiattack", "desc": "The scorpion makes three attacks: two with its claws and one with its sting.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 3, "healAmount": 0}, {"name": "Sting", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one creature. Hit: 7 (1d10 + 2) piercing damage, and the target must make a DC 12 Constitution saving throw, taking 22 (4d10) poison damage on a failed save, or half as much damage on a successful one.", "attackBonus": 4, "damageDice": "1d10", "damageBonus": 2, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Giant Sea Horse', 'Giant Sea Horse', 'Large', 'Beast', 'Unaligned', 13, 16, '3d10', '0 Ft., Swim 40 Ft.', 12, 15, 11, 2, 12, 5, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Passive Perception 11', '', '1/2', 100, 2, '[{"name": "Ram", "desc": "Melee Weapon Attack: +3 to hit, reach 5 ft., one target. Hit: 4 (1d6 + 1) bludgeoning damage.", "attackBonus": 3, "damageDice": "1d6", "damageBonus": 1, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Charge", "desc": "If the sea horse moves at least 20 ft. straight toward a target and then hits it with a ram attack on the same turn, the target takes an extra 7 (2d6) bludgeoning damage. If the target is a creature, it must succeed on a DC 11 Strength saving throw or be knocked prone.", "attackBonus": 0, "damageDice": "2d6", "damageBonus": 0, "damageType": "bludgeoning", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "str", "saveAbilityLabel": "Strength", "saveDC": 11, "rangeSquares": 4, "multiattackCount": 0, "healAmount": 0}, {"name": "Water Breathing", "desc": "The sea horse can breathe only underwater.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Giant Shark', 'Giant Shark', 'Huge', 'Beast', 'Unaligned', 13, 126, '11d12', 'Swim 50 Ft.', 23, 11, 21, 1, 10, 5, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +3', NULL, NULL, NULL, 'Blindsight 60 Ft., Passive Perception 13', '', '5', 1800, 3, '[{"name": "Bite", "desc": "Weapon Attack: +9 to hit, reach 5 ft., one target. Hit: 22 (3d10 + 6) piercing damage.", "attackBonus": 9, "damageDice": "3d10", "damageBonus": 6, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Blood Frenzy", "desc": "The shark has advantage on melee attack rolls against any creature that doesn\'t have all its hit points.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Water Breathing", "desc": "The shark can breathe only underwater.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Giant Spider', 'Giant Spider', 'Large', 'Beast', 'Unaligned', 14, 26, '4d10', '30 Ft., Climb 30 Ft.', 14, 16, 12, 2, 11, 4, NULL, NULL, NULL, NULL, NULL, NULL, 'Stealth +7', NULL, NULL, NULL, 'Blindsight 10 Ft., Darkvision 60 Ft., Passive Perception 10', '', '1', 200, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one creature. Hit: 7 (1d8 + 3) piercing damage, and the target must make a DC 11 Constitution saving throw, taking 9 (2d8) poison damage on a failed save, or half as much damage on a successful one. If the poison damage reduces the target to 0 hit points, the target is stable but poisoned for 1 hour, even after regaining hit points, and is paralyzed while poisoned in this way.", "attackBonus": 5, "damageDice": "1d8", "damageBonus": 3, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Web (Recharge 5-6)", "desc": "Ranged Weapon Attack: +5 to hit, range 30/60 ft., one creature. Hit: The target is restrained by webbing. As an action, the restrained target can make a DC 12 Strength check, bursting the webbing on a success. The webbing can also be attacked and destroyed (AC 10; hp 5; vulnerability to fire damage; immunity to bludgeoning, poison, and psychic damage).", "attackBonus": 5, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Spider Climb", "desc": "The spider can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Web Sense", "desc": "While in contact with a web, the spider knows the exact location of any other creature in contact with the same web.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Web Walker", "desc": "The spider ignores movement restrictions caused by webbing.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Giant Toad', 'Giant Toad', 'Large', 'Beast', 'Unaligned', 11, 39, '6d10', '20 Ft., Swim 40 Ft.', 15, 13, 13, 2, 10, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Darkvision 30 Ft., Passive Perception 10', '', '1', 200, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 7 (1d10 + 2) piercing damage plus 5 (1d10) poison damage, and the target is grappled (escape DC 13). Until this grapple ends, the target is restrained, and the toad can\'t bite another target.", "attackBonus": 4, "damageDice": "1d10", "damageBonus": 2, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Swallow", "desc": "The toad makes one bite attack against a Medium or smaller target it is grappling. If the attack hits, the target is swallowed, and the grapple ends. The swallowed target is blinded and restrained, it has total cover against attacks and other effects outside the toad, and it takes 10 (3d6) acid damage at the start of each of the toad\'s turns. The toad can have only one target swallowed at a time.\\nIf the toad dies, a swallowed creature is no longer restrained by it and can escape from the corpse using 5 feet of movement, exiting prone.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Amphibious", "desc": "The toad can breathe air and water", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Standing Leap", "desc": "The toad\'s long jump is up to 20 ft. and its high jump is up to 10 ft., with or without a running start.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
