    ('Giant Vulture', 'Giant Vulture', 'Large', 'Beast', 'Neutral Evil', 10, 22, '3d10', '10 Ft., Fly 60 Ft.', 15, 10, 15, 6, 12, 7, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +3', NULL, NULL, NULL, 'Passive Perception 13', 'understands Common but can\'t speak', '1', 200, 2, '[{"name": "Multiattack", "desc": "The vulture makes two attacks: one with its beak and one with its talons.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Beak", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 7 (2d4 + 2) piercing damage.", "attackBonus": 4, "damageDice": "2d4", "damageBonus": 2, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Talons", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 9 (2d6 + 2) slashing damage.", "attackBonus": 4, "damageDice": "2d6", "damageBonus": 2, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Keen Sight and Smell", "desc": "The vulture has advantage on Wisdom (Perception) checks that rely on sight or smell.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Pack Tactics", "desc": "The vulture has advantage on an attack roll against a creature if at least one of the vulture\'s allies is within 5 ft. of the creature and the ally isn\'t incapacitated.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
