    ('Gynosphinx', 'Gynosphinx', 'Large', 'Monstrosity', 'Lawful Neutral', 17, 136, '16d10', '40 Ft., Fly 60 Ft.', 18, 15, 16, 18, 18, 18, NULL, NULL, NULL, NULL, NULL, NULL, 'Arcana +12, History +12, Perception +8, Religion +8', 'Bludgeoning, Piercing, And Slashing From Nonmagical Weapons', 'Psychic; Charmed, Frightened', NULL, 'Truesight 120 Ft., Passive Perception 18', 'Common, Sphinx', '11', 7200, 4, '[{"name": "Multiattack", "desc": "The sphinx makes two claw attacks.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Claw", "desc": "Melee Weapon Attack: +9 to hit, reach 5 ft., one target. Hit: 13 (2d8 + 4) slashing damage.", "attackBonus": 9, "damageDice": "2d8", "damageBonus": 4, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Inscrutable", "desc": "The sphinx is immune to any effect that would sense its emotions or read its thoughts, as well as any divination spell that it refuses. Wisdom (Insight) checks made to ascertain the sphinx\'s intentions or sincerity have disadvantage.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Magic Weapons", "desc": "The sphinx\'s weapon attacks are magical.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Spellcasting", "desc": "The sphinx is a 9th-level spellcaster. Its spellcasting ability is Intelligence (spell save DC 16, +8 to hit with spell attacks). It requires no material components to cast its spells. The sphinx has the following wizard spells prepared:\\n\\n\\u2022 Cantrips (at will): mage hand, minor illusion, prestidigitation\\n\\u2022 1st level (4 slots): detect magic, identify, shield\\n\\u2022 2nd level (3 slots): darkness, locate object, suggestion\\n\\u2022 3rd level (3 slots): dispel magic, remove curse, tongues\\n\\u2022 4th level (3 slots): banishment, greater invisibility\\n\\u2022 5th level (1 slot): legend lore", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Claw Attack", "desc": "The sphinx makes one claw attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Teleport (Costs 2 Actions)", "desc": "The sphinx magically teleports, along with any equipment it is wearing or carrying, up to 120 feet to an unoccupied space it can see.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Cast a Spell (Costs 3 Actions)", "desc": "The sphinx casts a spell from its list of prepared spells, using a spell slot as normal.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL);
