    ('Rug of Smothering', 'Rug of Smothering', 'Large', 'Construct', 'Unaligned', 12, 33, '6d10', '10 Ft.', 17, 14, 10, 1, 3, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Poison, Psychic; Blinded, Charmed, Deafened, Frightened, Paralyzed, Petrified, Poisoned', NULL, 'Blindsight 60 Ft. (blind Beyond This Radius), Passive Perception 6', '', '2', 450, 2, '[{"name": "Smother", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one Medium or smaller creature. Hit: The creature is grappled (escape DC 13). Until this grapple ends, the target is restrained, blinded, and at risk of suffocating, and the rug can\'t smother another target. In addition, at the start of each of the target\'s turns, the target takes 10 (2d6 + 3) bludgeoning damage.", "attackBonus": 0, "damageDice": "2d6", "damageBonus": 3, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Antimagic Susceptibility", "desc": "The rug is incapacitated while in the area of an antimagic field. If targeted by dispel magic, the rug must succeed on a Constitution saving throw against the caster\'s spell save DC or fall unconscious for 1 minute.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Damage Transfer", "desc": "While it is grappling a creature, the rug takes only half the damage dealt to it, and the creature grappled by the rug takes the other half.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "False Appearance", "desc": "While the rug remains motionless, it is indistinguishable from a normal rug.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
