    ('Scorpion', 'Scorpion', 'Tiny', 'Beast', 'Unaligned', 11, 1, '1d4', '10 Ft.', 2, 11, 8, 1, 8, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Blindsight 10 Ft., Passive Perception 9', '', '0', 10, 2, '[{"name": "Sting", "desc": "Melee Weapon Attack: +2 to hit, reach 5 ft., one creature. Hit: 1 piercing damage, and the target must make a DC 9 Constitution saving throw, taking 4 (1d8) poison damage on a failed save, or half as much damage on a successful one.", "attackBonus": 2, "damageDice": "", "damageBonus": 1, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
