    ('Sea Horse', 'Sea Horse', 'Tiny', 'Beast', 'Unaligned', 11, 1, '1d4', 'Swim 20 Ft.', 1, 12, 8, 1, 10, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Passive Perception 10', '', '0', 10, 2, NULL, '[{"name": "Water Breathing", "desc": "The sea horse can breathe only underwater.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
