    ('Shrieker', 'Shrieker', 'Medium', 'Plant', 'Unaligned', 5, 13, '3d8', '0 Ft.', 1, 1, 10, 1, 3, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '; Blinded, Deafened, Frightened', NULL, 'Blindsight 30 Ft. (blind Beyond This Radius), Passive Perception 6', '', '0', 10, 2, '[{"name": "Shriek", "desc": "When bright light or a creature is within 30 feet of the shrieker, it emits a shriek audible within 300 feet of it. The shrieker continues to shriek until the disturbance moves out of range and for 1d4 of the shrieker\'s turns afterward", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "False Appearance", "desc": "While the shrieker remains motionless, it is indistinguishable from an ordinary fungus.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Spider', 'Spider', 'Tiny', 'Beast', 'Unaligned', 12, 1, '1d4', '20 Ft., Climb 20 Ft.', 2, 14, 8, 1, 10, 2, NULL, NULL, NULL, NULL, NULL, NULL, 'Stealth +4', NULL, NULL, NULL, 'Darkvision 30 Ft., Passive Perception 12', '', '0', 10, 2, '[{"name": "Bite", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one creature. Hit: 1 piercing damage, and the target must succeed on a DC 9 Constitution saving throw or take 2 (1d4) poison damage.", "attackBonus": 4, "damageDice": "", "damageBonus": 1, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Spider Climb", "desc": "The spider can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Web Sense", "desc": "While in contact with a web, the spider knows the exact location of any other creature in contact with the same web.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Web Walker", "desc": "The spider ignores movement restrictions caused by webbing.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
INSERT INTO monsters (group_name, name, size, creature_type, alignment, armor_class, hit_points, hit_dice, speed, str, dex, con, int_score, wis, cha, str_save, dex_save, con_save, int_save, wis_save, cha_save, skills, resistances, immunities, vulnerabilities, senses, languages, cr, xp, proficiency_bonus, actions_json, special_abilities_json, legendary_actions_json, reactions_json) VALUES
    ('Succubus/Incubus', 'Succubus/Incubus', 'Medium', 'Fiend (Shapechanger)', 'Neutral Evil', 15, 66, '12d8', '30 Ft., Fly 60 Ft.', 8, 17, 13, 15, 12, 20, NULL, NULL, NULL, NULL, NULL, NULL, 'Deception +9, Insight +5, Perception +5, Persuasion +9, Stealth +7', 'Cold, Fire, Lightning, Poison; Bludgeoning, Piercing, And Slashing From Nonmagical Weapons', NULL, NULL, 'Darkvision 60 Ft., Passive Perception 15', 'Abyssal, Common, Infernal, telepathy 60 ft.', '4', 1100, 2, '[{"name": "Claw (Fiend Form Only)", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 6 (1d6 + 3) slashing damage.", "attackBonus": 5, "damageDice": "1d6", "damageBonus": 3, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Charm", "desc": "One humanoid the fiend can see within 30 feet of it must succeed on a DC 15 Wisdom saving throw or be magically charmed for 1 day. The charmed target obeys the fiend\'s verbal or telepathic commands. If the target suffers any harm or receives a suicidal command, it can repeat the saving throw, ending the effect on a success. If the target successfully saves against the effect, or if the effect on it ends, the target is immune to this fiend\'s Charm for the next 24 hours.\\nThe fiend can have only one target charmed at a time. If it charms another, the effect on the previous target ends.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Draining Kiss", "desc": "The fiend kisses a creature charmed by it or a willing creature. The target must make a DC 15 Constitution saving throw against this magic, taking 32 (5d10 + 5) psychic damage on a failed save, or half as much damage on a successful one. The target\'s hit point maximum is reduced by an amount equal to the damage taken. This reduction lasts until the target finishes a long rest. The target dies if this effect reduces its hit point maximum to 0.", "attackBonus": 0, "damageDice": "5d10", "damageBonus": 5, "damageType": "psychic", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "con", "saveAbilityLabel": "Constitution", "saveDC": 15, "rangeSquares": 6, "multiattackCount": 0, "healAmount": 0}, {"name": "Etherealness", "desc": "The fiend magically enters the Ethereal Plane from the Material Plane, or vice versa.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Telepathic Bond", "desc": "The fiend ignores the range restriction on its telepathy when communicating with a creature it has charmed. The two don\'t even need to be on the same plane of existence.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Shapechanger", "desc": "The fiend can use its action to polymorph into a Small or Medium humanoid, or back into its true form. Without wings, the fiend loses its flying speed. Other than its size and speed, its statistics are the same in each form. Any equipment it is wearing or carrying isn\'t transformed. It reverts to its true form if it dies.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
