    ('Swarm of Bats', 'Swarm of Bats', 'Medium', 'Swarm Of Tiny Beasts', 'Unaligned', 12, 22, '5d8', '0 Ft., Fly 30 Ft.', 5, 15, 10, 2, 12, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bludgeoning, Piercing, Slashing', '; Charmed, Frightened, Grappled, Paralyzed, Petrified, Prone, Restrained, Stunned', NULL, 'Blindsight 60 Ft., Passive Perception 11', '', '1/4', 50, 2, '[{"name": "Bites", "desc": "Melee Weapon Attack: +4 to hit, reach 0 ft., one creature in the swarm\'s space. Hit: 5 (2d4) piercing damage, or 2 (1d4) piercing damage if the swarm has half of its hit points or fewer.", "attackBonus": 4, "damageDice": "2d4", "damageBonus": 0, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', '[{"name": "Echolocation", "desc": "The swarm can\'t use its blindsight while deafened.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Keen Hearing", "desc": "The swarm has advantage on Wisdom (Perception) checks that rely on hearing.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Swarm", "desc": "The swarm can occupy another creature\'s space and vice versa, and the swarm can move through any opening large enough for a Tiny bat. The swarm can\'t regain hit points or gain temporary hit points.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL);
