    ('Tyrannosaurus Rex', 'Tyrannosaurus Rex', 'Huge', 'Beast', 'Unaligned', 13, 136, '13d12', '50 Ft.', 25, 10, 19, 2, 12, 9, NULL, NULL, NULL, NULL, NULL, NULL, 'Perception +4', NULL, NULL, NULL, 'Passive Perception 14', '', '8', 3900, 3, '[{"name": "Multiattack", "desc": "The tyrannosaurus makes two attacks: one with its bite and one with its tail. It can\'t make both attacks against the same target.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Bite", "desc": "Melee Weapon Attack: +10 to hit, reach 10 ft., one target. Hit: 33 (4d12 + 7) piercing damage. If the target is a Medium or smaller creature, it is grappled (escape DC 17). Until this grapple ends, the target is restrained, and the tyrannosaurus can\'t bite another target.", "attackBonus": 10, "damageDice": "4d12", "damageBonus": 7, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Tail", "desc": "Melee Weapon Attack: +10 to hit, reach 10 ft., one target. Hit: 20 (3d8 + 7) bludgeoning damage.", "attackBonus": 10, "damageDice": "3d8", "damageBonus": 7, "damageType": "bludgeoning", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
