    ('Veteran', 'Veteran', 'Medium', 'Humanoid (Any Race)', 'Any Alignment', 17, 58, '9d8', '30 Ft.', 16, 13, 14, 10, 11, 10, NULL, NULL, NULL, NULL, NULL, NULL, 'Athletics +5, Perception +2', NULL, NULL, NULL, 'Passive Perception 12', 'any one language (usually Common)', '3', 700, 2, '[{"name": "Multiattack", "desc": "The veteran makes two longsword attacks. If it has a shortsword drawn, it can also make a shortsword attack.", "attackBonus": 0, "damageDice": "", "damageBonus": 0, "damageType": "", "category": "", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 2, "healAmount": 0}, {"name": "Longsword", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 7 (1d8 + 3) slashing damage, or 8 (1d10 + 3) slashing damage if used with two hands.", "attackBonus": 5, "damageDice": "1d8", "damageBonus": 3, "damageType": "slashing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Shortsword", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 6 (1d6 + 3) piercing damage.", "attackBonus": 5, "damageDice": "1d6", "damageBonus": 3, "damageType": "piercing", "category": "melee", "normalRange": 0, "longRange": 0, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}, {"name": "Heavy Crossbow", "desc": "Ranged Weapon Attack: +3 to hit, range 100/400 ft., one target. Hit: 6 (1d10 + 1) piercing damage.", "attackBonus": 3, "damageDice": "1d10", "damageBonus": 1, "damageType": "piercing", "category": "ranged", "normalRange": 20, "longRange": 80, "saveAbility": "", "saveAbilityLabel": "", "saveDC": 0, "rangeSquares": 0, "multiattackCount": 0, "healAmount": 0}]', NULL, NULL, NULL);
